import{_ as e,o as r,c as l,ak as t}from"./chunks/framework.DFpMdDbl.js";const g=JSON.parse('{"title":"区块漏斗","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/upgradeable_hoppers.md","filePath":"plugins/upgradeable_hoppers.md","lastUpdated":1777376573000}'),o={name:"plugins/upgradeable_hoppers.md"};function s(i,a,p,n,d,c){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="区块漏斗" tabindex="-1">区块漏斗 <a class="header-anchor" href="#区块漏斗" aria-label="Permalink to “区块漏斗”">​</a></h1><div class="tip custom-block"><p class="custom-block-title">提示</p><p>使用<code>/uhoppers help</code>获得这个插件的命令的用法。</p></div><h2 id="区块漏斗是什么" tabindex="-1">区块漏斗是什么？ <a class="header-anchor" href="#区块漏斗是什么" aria-label="Permalink to “区块漏斗是什么？”">​</a></h2><p><strong>Upgradeable Hoppers</strong> 是一款为 Minecraft 服务器（Spigot/Bukkit）设计的优化插件。其核心功能是<strong>用单个高性能漏斗替代复杂的漏斗链</strong>，从而显著降低服务器因实体漏斗产生的 Tick 延迟（TPS Lag），提升服务器性能。</p><p><mark>这个插件目前并没有官方中文名，我们暂称为区块漏斗，但“升级漏斗”这样的名字也是这个插件。</mark></p><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to “核心特性”">​</a></h2><ul><li>自动拾取整个区块内掉落在地面上的物品</li><li>无需依赖水流或漏斗矿车进行物品收集</li><li>支持在自己的领土或被信任的领土中使用</li><li>领土中被信任的其他成员或领土拥有者可以编辑区块漏斗的设置</li></ul><h2 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to “操作”">​</a></h2><p><code>/uhoppers list</code> - 查看并管理已放置的升级漏斗</p><p><code>/uhoppers get</code> - 购买漏斗（默认类型：normal 或 chunk）</p><p><strong>左键点击区块漏斗</strong> - 打开交互菜单</p><p><strong>右键点击升级漏斗</strong> - 打开漏斗界面</p><p><strong>潜行 + 使用工具破坏</strong> - 回收已放置的升级漏斗</p><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ul><li>当前版本为测试阶段，漏斗价格可能会调整，并非最终定价</li><li>漏斗只能在<strong>自己的领土</strong>或<strong>被信任的领土</strong>中使用</li><li>漏斗功能在权限范围内自动运行，无需玩家手动干预收集流程</li></ul>',15)])])}const _=e(o,[["render",s]]);export{g as __pageData,_ as default};
